#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
#define getchar() (p1==p2&&(p2=(p1=BUF)+fread(BUF,1,1<<21,stdin),p1==p2)?EOF:*p1++)
char BUF[1<<23],*p1=BUF,*p2=BUF;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=525020;int head[N],des[N],nxt[N],cgt,V[N],n;
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
bool buf[N<<5];int mxd[N],mxs[N],S[N];long long ans;
inline void dfs0(const int &u){grep(u,i){int v=des[i];dfs0(v);mxd[u]<mxd[v]?mxd[u]=mxd[mxs[u]=v]:0;}++mxd[u];}
inline void dfs1(const int &u,bool *cnt)
{
	memset(cnt,0,1024);if(mxs[u])dfs1(mxs[u],cnt+1),cnt[0]=cnt[1024];
	cnt[V[u]&1023]^=1;grep(u,i)if(des[i]!=mxs[u])
	{
		int v=des[i];bool *tmp=cnt+1025;dfs1(v,tmp);
		rep(1,1023,i)cnt[i]^=tmp[i-1];cnt[0]^=tmp[1023];
	}
	int tmp=0;rep(1,1023,i)if(cnt[i])tmp^=i;ans+=tmp;
}
int stk[N],top;inline void dfs2(const int &u)
{
	stk[++top]=u;int v=(V[u]&2047),t;
if(v<1024)t=top-1024+v;else{S[u]^=1024;t=top-2048+v;}
while(t>0){S[stk[t]]^=1024;t-=1024;}
v=(V[u]&4095);
if(v<2048)t=top-2048+v;else{S[u]^=2048;t=top-4096+v;}
while(t>0){S[stk[t]]^=2048;t-=2048;}
v=(V[u]&8191);
if(v<4096)t=top-4096+v;else{S[u]^=4096;t=top-8192+v;}
while(t>0){S[stk[t]]^=4096;t-=4096;}
v=(V[u]&16383);
if(v<8192)t=top-8192+v;else{S[u]^=8192;t=top-16384+v;}
while(t>0){S[stk[t]]^=8192;t-=8192;}
v=(V[u]&32767);
if(v<16384)t=top-16384+v;else{S[u]^=16384;t=top-32768+v;}
while(t>0){S[stk[t]]^=16384;t-=16384;}
v=(V[u]&65535);
if(v<32768)t=top-32768+v;else{S[u]^=32768;t=top-65536+v;}
while(t>0){S[stk[t]]^=32768;t-=32768;}
v=(V[u]&131071);
if(v<65536)t=top-65536+v;else{S[u]^=65536;t=top-131072+v;}
while(t>0){S[stk[t]]^=65536;t-=65536;}
v=(V[u]&262143);
if(v<131072)t=top-131072+v;else{S[u]^=131072;t=top-262144+v;}
while(t>0){S[stk[t]]^=131072;t-=131072;}
v=(V[u]&524287);
if(v<262144)t=top-262144+v;else{S[u]^=262144;t=top-524288+v;}
while(t>0){S[stk[t]]^=262144;t-=262144;}
v=(V[u]&1048575);
if(v<524288)t=top-524288+v;else{S[u]^=524288;t=top-1048576+v;}
while(t>0){S[stk[t]]^=524288;t-=524288;}
v=(V[u]&2097151);
if(v<1048576)t=top-1048576+v;else{S[u]^=1048576;t=top-2097152+v;}
while(t>0){S[stk[t]]^=1048576;t-=1048576;}
	grep(u,i)dfs2(des[i]);--top;
}

int main()
{
//	FIN("tree12.in");
	n=read();rep(1,n,i)V[i]=read();rep(2,n,i)ins(read(),i);
	dfs0(1);dfs1(1,buf);
	dfs2(1);
	drep(n,1,u){grep(u,i)S[u]^=S[des[i]];ans+=S[u];}
	printf("%lld\n",ans);return 0;
}
